import { createContextHook } from '@universe-design/react-provider';
import { createContext, useContext } from 'react';
import { useCssScope } from '../config-provider';
import * as React from 'react';
import type { ChartPosition, MetricsProps } from './Metrics';

interface MetricsContextType extends Required<Pick<MetricsProps, 'size'> & ChartPosition> {
  rootCssScope: (suffix?: string) => string;
}

const { useContext: useMetricsContext, Provider: MetricsContextProvider } = createContextHook<MetricsContextType>(
  'MetricsContext',
  {
    strict: true,
    customizedContextMethods: {
      createContext,
      useContext,
    },
  },
);

const MetricsProvider = ({
  size = 'medium',
  position = 'afterAll',
  children,
}: React.PropsWithChildren<Pick<MetricsProps, 'size'> & ChartPosition>) => {
  const rootCssScope = useCssScope('metrics');

  return (
    <MetricsContextProvider
      value={{
        rootCssScope,
        size,
        position,
      }}
    >
      {children}
    </MetricsContextProvider>
  );
};

export { useMetricsContext, MetricsProvider };
